module top_module(cout, resetn, clk, d) ;input [27:0] d;
	input resetn, clk;
	output cout; 

	reg [27:0] count;

	always @ (posedge clk)
	begin 
		if (resetn == 1'b0)
		begin
			count <= d;
		end

		else 
		begin 
			if (count == 0)
			begin
				count <= d;
			end
			else
			begin
				count <= count - 1;
			end
		end
	end

	wire neg_count_reached_zero = (count == 0);
	assign cout = neg_count_reached_zero ? 1 : 0;endmodule
